[
  {
    "text": "JanusMesh is a fast, training-free framework for generating text-driven 3D visual illusions that produce dual-semantic 3D objects in 3-5 minutes.",
    "topic": "3D visual illusion generation"
  },
  {
    "text": "The JanusMesh approach uses a cross-space dual-branch denoising process to align 3D latents with CLIP guidance and blend Signed Distance Fields (SDFs) for seamless geometric fusion.",
    "topic": "cross-space denoising"
  },
  {
    "text": "JanusMesh incorporates a view-conditioned texture synthesis module that projects and aggregates view-specific 2D diffusion priors onto the fused geometry.",
    "topic": "view-conditioned texture synthesis"
  },
  {
    "text": "Experiments show JanusMesh significantly outperforms existing methods in geometric integrity, semantic recognizability, and efficiency for generating 3D visual illusions.",
    "topic": "performance comparison"
  },
  {
    "text": "The project page for JanusMesh is available at https://siang1105.github.io/JanusMesh.github.io/",
    "topic": "project page"
  }
]
